const item = $input.first();
const json = item?.json ?? {};
const markdown = String(json.response ?? '').replace(/\r\n/g, '\n');

if (!markdown.trim()) {
  throw new Error('Requirements Markdown is missing, cannot generate PDF.');
}

const PAGE_WIDTH = 595;
const PAGE_HEIGHT = 842;
const MARGIN_X = 48;
const MARGIN_Y = 52;
const CONTENT_WIDTH = PAGE_WIDTH - (MARGIN_X * 2);
const LINE_GAP = 4;
const TABLE_FONT_SIZE = 11;
const TABLE_LINE_HEIGHT = 14;
const TABLE_CELL_PADDING_X = 5;
const TABLE_CELL_PADDING_Y = 4;

const WIN_ANSI_MAP = {
  '\u20AC': 0x80,
  '\u201A': 0x82,
  '\u0192': 0x83,
  '\u201E': 0x84,
  '\u2026': 0x85,
  '\u2020': 0x86,
  '\u2021': 0x87,
  '\u02C6': 0x88,
  '\u2030': 0x89,
  '\u0160': 0x8A,
  '\u2039': 0x8B,
  '\u0152': 0x8C,
  '\u017D': 0x8E,
  '\u2018': 0x91,
  '\u2019': 0x92,
  '\u201C': 0x93,
  '\u201D': 0x94,
  '\u2022': 0x95,
  '\u2013': 0x96,
  '\u2014': 0x97,
  '\u02DC': 0x98,
  '\u2122': 0x99,
  '\u0161': 0x9A,
  '\u203A': 0x9B,
  '\u0153': 0x9C,
  '\u017E': 0x9E,
  '\u0178': 0x9F,
};

function stripInlineMarkdown(value) {
  return String(value ?? '')
    .replace(/`([^`]+)`/g, '$1')
    .replace(/\*\*([^*]+)\*\*/g, '$1')
    .replace(/__([^_]+)__/g, '$1')
    .replace(/\*([^*]+)\*/g, '$1')
    .replace(/_([^_]+)_/g, '$1')
    .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '$1 ($2)');
}

function normalizeText(value) {
  return String(value ?? '')
    .normalize('NFC')
    .replace(/\u0000/g, '')
    .replace(/[\u200B-\u200D\uFEFF]/g, '')
    .replace(/\t/g, '    ');
}

function collapseSpaces(value) {
  return String(value ?? '').replace(/\s+/g, ' ').trim();
}

function estimateMaxChars(fontSize, indent) {
  const usable = Math.max(60, CONTENT_WIDTH - indent);
  const avgCharWidth = Math.max(4.6, fontSize * 0.5);
  return Math.max(18, Math.floor(usable / avgCharWidth));
}

function wrapText(text, maxChars) {
  const clean = collapseSpaces(text);
  const limit = Math.max(4, Math.floor(maxChars || 0));
  if (!clean) return [''];

  const lines = [];
  let remaining = clean;

  while (remaining.length > limit) {
    let breakAt = remaining.lastIndexOf(' ', limit);
    if (breakAt < Math.floor(limit * 0.5)) {
      breakAt = limit;
    }

    const segment = remaining.slice(0, breakAt).trim();
    if (segment) {
      lines.push(segment);
      remaining = remaining.slice(breakAt).trimStart();
    } else {
      lines.push(remaining.slice(0, limit));
      remaining = remaining.slice(limit);
    }
  }

  if (remaining) lines.push(remaining);
  return lines.length ? lines : [''];
}

function toWinAnsiString(value) {
  const input = String(value ?? '').normalize('NFC');
  let out = '';

  for (const char of input) {
    const code = char.codePointAt(0);

    if (code <= 0xff) {
      out += String.fromCharCode(code);
      continue;
    }

    if (WIN_ANSI_MAP[char] !== undefined) {
      out += String.fromCharCode(WIN_ANSI_MAP[char]);
      continue;
    }

    if (char === '?') {
      out += '->';
      continue;
    }

    const noDiacritics = char.normalize('NFKD').replace(/[\u0300-\u036f]/g, '');
    if (noDiacritics && noDiacritics.codePointAt(0) <= 0xff) {
      out += String.fromCharCode(noDiacritics.codePointAt(0));
    }
  }

  return out;
}

function escapePdfLiteral(value) {
  return String(value ?? '')
    .replace(/\\/g, '\\\\')
    .replace(/\(/g, '\\(')
    .replace(/\)/g, '\\)');
}

function isTableSeparator(line) {
  const inner = String(line ?? '').trim().replace(/^\|/, '').replace(/\|$/, '');
  if (!inner) return false;
  const cells = inner.split('|').map((c) => c.trim());
  return cells.length > 0 && cells.every((cell) => /^:?-{3,}:?$/.test(cell));
}

function parseTableLine(line) {
  const inner = String(line ?? '').trim().replace(/^\|/, '').replace(/\|$/, '');
  return inner.split('|').map((cell) => collapseSpaces(stripInlineMarkdown(cell)));
}

function buildTableLayout(tableRows, columnCount) {
  const safeRows = tableRows.map((row) => Array.from({ length: columnCount }, (_, i) => collapseSpaces(row[i] ?? '')));

  const maxCharsByCol = Array.from({ length: columnCount }, () => 8);
  for (const row of safeRows) {
    for (let i = 0; i < columnCount; i += 1) {
      maxCharsByCol[i] = Math.max(maxCharsByCol[i], Math.min(48, row[i].length || 1));
    }
  }

  let widths = maxCharsByCol.map((chars) => Math.max(50, chars * 5.1 + (TABLE_CELL_PADDING_X * 2)));
  const total = widths.reduce((acc, v) => acc + v, 0);

  if (total > CONTENT_WIDTH) {
    const scale = CONTENT_WIDTH / total;
    widths = widths.map((w) => Math.max(44, w * scale));
    const scaledTotal = widths.reduce((acc, v) => acc + v, 0);
    if (scaledTotal > CONTENT_WIDTH) {
      widths[widths.length - 1] -= (scaledTotal - CONTENT_WIDTH);
    }
  }

  const rowLayouts = safeRows.map((row, rowIndex) => {
    const cellLines = row.map((cell, col) => {
      const maxChars = Math.max(3, Math.floor((widths[col] - (TABLE_CELL_PADDING_X * 2)) / 5.8) - 1);
      return wrapText(cell, maxChars);
    });

    const maxLineCount = Math.max(...cellLines.map((c) => c.length));
    return {
      font: rowIndex === 0 ? 'F2' : 'F1',
      fontSize: TABLE_FONT_SIZE,
      cellLines,
      height: (maxLineCount * TABLE_LINE_HEIGHT) + (TABLE_CELL_PADDING_Y * 2),
    };
  });

  return { widths, rowLayouts };
}

function buildLayout(mdText) {
  const rows = [];
  const lines = normalizeText(mdText).split('\n');

  const firstMeaningful = lines
    .map((line) => collapseSpaces(stripInlineMarkdown(line)))
    .find((line) => !!line) ?? 'Requirements Specification';

  const firstHeading = firstMeaningful.match(/^(#{1,6})\s+(.+)$/);
  const title = firstHeading
    ? collapseSpaces(firstHeading[2])
    : collapseSpaces(firstMeaningful.replace(/^\*\*(.*)\*\*$/, '$1'));

  rows.push({ text: title, font: 'F2', fontSize: 24, lineHeight: 30, indent: 0, extraAfter: 2 });
  rows.push({ text: 'Requirements Specification Document', font: 'F1', fontSize: 12, lineHeight: 16, indent: 0, extraAfter: 8 });
  rows.push({ type: 'rule' });
  rows.push({ type: 'spacer', amount: 8 });

  let titleConsumed = false;

  for (let idx = 0; idx < lines.length; idx += 1) {
    const rawLine = lines[idx];
    const line = String(rawLine ?? '').replace(/\s+$/g, '');
    const trimmed = line.trim();
    const cleanTrimmed = collapseSpaces(stripInlineMarkdown(trimmed.replace(/^#{1,6}\s+/, '').replace(/^\*\*(.*)\*\*$/, '$1')));

    if (!titleConsumed && cleanTrimmed && cleanTrimmed === title) {
      titleConsumed = true;
      continue;
    }

    if (!trimmed) {
      rows.push({ type: 'spacer', amount: 6 });
      continue;
    }

    if (trimmed.startsWith('|')) {
      const tableLines = [trimmed];
      let probe = idx + 1;
      while (probe < lines.length) {
        const candidate = String(lines[probe] ?? '').trim();
        if (!candidate.startsWith('|')) break;
        tableLines.push(candidate);
        probe += 1;
      }

      if (tableLines.length >= 2 && isTableSeparator(tableLines[1])) {
        const parsed = tableLines
          .filter((lineValue, lineIndex) => !(lineIndex === 1 && isTableSeparator(lineValue)))
          .map(parseTableLine);

        const columnCount = parsed.reduce((acc, row) => Math.max(acc, row.length), 0);
        if (parsed.length > 0 && columnCount > 0) {
          rows.push({ type: 'table', rows: parsed, columnCount });
          rows.push({ type: 'spacer', amount: 8 });
          idx = probe - 1;
          continue;
        }
      }
    }

    if (/^---+$/.test(trimmed) || /^___+$/.test(trimmed) || /^\*\*\*+$/.test(trimmed)) {
      rows.push({ type: 'rule' });
      rows.push({ type: 'spacer', amount: 8 });
      continue;
    }

    const heading = trimmed.match(/^(#{1,6})\s+(.*)$/);
    if (heading) {
      const level = Math.min(6, heading[1].length);
      const sizeMap = { 1: 20, 2: 16, 3: 14, 4: 12, 5: 11, 6: 10 };
      rows.push({
        text: collapseSpaces(stripInlineMarkdown(heading[2])),
        font: 'F2',
        fontSize: sizeMap[level],
        lineHeight: sizeMap[level] + 4,
        indent: 0,
        extraBefore: level <= 2 ? 8 : 4,
        extraAfter: level <= 2 ? 4 : 2,
      });
      continue;
    }

    const bullet = trimmed.match(/^[-*+]\s+(.*)$/);
    if (bullet) {
      rows.push({ text: collapseSpaces(stripInlineMarkdown(bullet[1])), font: 'F1', fontSize: 12, lineHeight: 17, indent: 18, bullet: '- ' });
      continue;
    }

    const ordered = trimmed.match(/^(\d+[.)])\s+(.*)$/);
    if (ordered) {
      rows.push({ text: collapseSpaces(stripInlineMarkdown(ordered[2])), font: 'F1', fontSize: 12, lineHeight: 17, indent: 22, bullet: ordered[1] + ' ' });
      continue;
    }

    rows.push({ text: collapseSpaces(stripInlineMarkdown(trimmed)), font: 'F1', fontSize: 12, lineHeight: 17, indent: 0 });
  }

  return rows;
}

function paginate(rows) {
  const pages = [];
  let currentPage = [];
  let y = PAGE_HEIGHT - MARGIN_Y;

  function pushPage() {
    pages.push(currentPage);
    currentPage = [];
    y = PAGE_HEIGHT - MARGIN_Y;
  }

  for (const row of rows) {
    if (row.type === 'spacer') {
      y -= row.amount;
      if (y < MARGIN_Y) pushPage();
      continue;
    }

    if (row.type === 'rule') {
      y -= 8;
      if (y < MARGIN_Y) pushPage();
      currentPage.push({ type: 'line', x1: MARGIN_X, y1: y, x2: PAGE_WIDTH - MARGIN_X, y2: y, width: 0.2 });
      y -= 12;
      if (y < MARGIN_Y) pushPage();
      continue;
    }

    if (row.type === 'table') {
      const table = buildTableLayout(row.rows, row.columnCount);
      const xBreaks = [MARGIN_X];
      for (const w of table.widths) xBreaks.push(xBreaks[xBreaks.length - 1] + w);

      for (let r = 0; r < table.rowLayouts.length; r += 1) {
        const rowLayout = table.rowLayouts[r];
        const rowHeight = rowLayout.height;

        if ((y - rowHeight) < MARGIN_Y) pushPage();

        const top = y;
        const bottom = y - rowHeight;

        currentPage.push({ type: 'line', x1: xBreaks[0], y1: top, x2: xBreaks[xBreaks.length - 1], y2: top, width: 0.6 });
        currentPage.push({ type: 'line', x1: xBreaks[0], y1: bottom, x2: xBreaks[xBreaks.length - 1], y2: bottom, width: 0.6 });

        for (let c = 0; c < xBreaks.length; c += 1) {
          currentPage.push({ type: 'line', x1: xBreaks[c], y1: top, x2: xBreaks[c], y2: bottom, width: 0.4 });
        }

        for (let c = 0; c < rowLayout.cellLines.length; c += 1) {
          const linesInCell = rowLayout.cellLines[c];
          let textY = top - TABLE_CELL_PADDING_Y - TABLE_FONT_SIZE;
          for (const segment of linesInCell) {
            currentPage.push({
              type: 'text',
              text: segment,
              font: rowLayout.font,
              fontSize: rowLayout.fontSize,
              x: xBreaks[c] + TABLE_CELL_PADDING_X,
              y: textY,
            });
            textY -= TABLE_LINE_HEIGHT;
          }
        }

        y = bottom - 4;
        if (y < MARGIN_Y) pushPage();
      }
      continue;
    }

    y -= row.extraBefore ?? 0;
    if (y < MARGIN_Y) pushPage();

    const prefix = row.bullet ?? '';
    const bodyMaxChars = estimateMaxChars(row.fontSize, row.indent);
    const wrapped = wrapText(row.text, Math.max(12, bodyMaxChars - prefix.length));

    for (let i = 0; i < wrapped.length; i += 1) {
      const text = (i === 0 ? prefix : ' '.repeat(prefix.length)) + wrapped[i];
      currentPage.push({ type: 'text', text, font: row.font, fontSize: row.fontSize, x: MARGIN_X + row.indent, y });
      y -= row.lineHeight;
      if (y < MARGIN_Y) pushPage();
    }

    y -= (row.extraAfter ?? LINE_GAP);
    if (y < MARGIN_Y) pushPage();
  }

  if (currentPage.length === 0) {
    currentPage.push({ type: 'text', text: '(empty document)', font: 'F1', fontSize: 11, x: MARGIN_X, y: PAGE_HEIGHT - MARGIN_Y });
  }

  pages.push(currentPage);
  return pages;
}

function pageToStream(pageRows) {
  const lines = [];

  for (const row of pageRows) {
    if (row.type === 'line') {
      lines.push((row.width ?? 0.2).toFixed(2) + ' w');
      lines.push(row.x1.toFixed(2) + ' ' + row.y1.toFixed(2) + ' m');
      lines.push(row.x2.toFixed(2) + ' ' + row.y2.toFixed(2) + ' l');
      lines.push('S');
      continue;
    }

    const safe = escapePdfLiteral(toWinAnsiString(row.text || ''));
    lines.push('BT');
    lines.push('/' + row.font + ' ' + row.fontSize + ' Tf');
    lines.push('1 0 0 1 ' + row.x.toFixed(2) + ' ' + row.y.toFixed(2) + ' Tm');
    lines.push('(' + safe + ') Tj');
    lines.push('ET');
  }

  return lines.join('\n');
}

function buildPdfDocument(pageStreams) {
  const objects = [];
  const pageStart = 5;
  const contentStart = pageStart + pageStreams.length;
  const pageRefs = pageStreams.map((_, i) => (pageStart + i) + ' 0 R').join(' ');

  objects[1] = '<< /Type /Catalog /Pages 2 0 R >>';
  objects[2] = '<< /Type /Pages /Kids [' + pageRefs + '] /Count ' + pageStreams.length + ' >>';
  objects[3] = '<< /Type /Font /Subtype /Type1 /BaseFont /Times-Roman /Encoding /WinAnsiEncoding >>';
  objects[4] = '<< /Type /Font /Subtype /Type1 /BaseFont /Times-Bold /Encoding /WinAnsiEncoding >>';

  for (let i = 0; i < pageStreams.length; i += 1) {
    const pageObj = pageStart + i;
    const contentObj = contentStart + i;
    objects[pageObj] = [
      '<< /Type /Page',
      '/Parent 2 0 R',
      '/MediaBox [0 0 ' + PAGE_WIDTH + ' ' + PAGE_HEIGHT + ']',
      '/Resources << /Font << /F1 3 0 R /F2 4 0 R >> >>',
      '/Contents ' + contentObj + ' 0 R',
      '>>',
    ].join(' ');

    const stream = pageStreams[i];
    const len = Buffer.byteLength(stream, 'latin1');
    objects[contentObj] = '<< /Length ' + len + ' >>\nstream\n' + stream + '\nendstream';
  }

  const maxObject = objects.length - 1;
  let pdf = '%PDF-1.4\n';
  const offsets = [0];

  for (let i = 1; i <= maxObject; i += 1) {
    offsets[i] = Buffer.byteLength(pdf, 'latin1');
    pdf += i + ' 0 obj\n' + objects[i] + '\nendobj\n';
  }

  const xrefOffset = Buffer.byteLength(pdf, 'latin1');
  pdf += 'xref\n0 ' + (maxObject + 1) + '\n';
  pdf += '0000000000 65535 f \n';

  for (let i = 1; i <= maxObject; i += 1) {
    const offset = String(offsets[i]).padStart(10, '0');
    pdf += offset + ' 00000 n \n';
  }

  pdf += 'trailer\n<< /Size ' + (maxObject + 1) + ' /Root 1 0 R >>\n';
  pdf += 'startxref\n' + xrefOffset + '\n%%EOF';
  return Buffer.from(pdf, 'latin1');
}

const rows = buildLayout(markdown);
const pages = paginate(rows);
const streams = pages.map(pageToStream);
const pdfBuffer = buildPdfDocument(streams);

return [{
