function parseCandidate(raw) {
  try {
    const parsed = JSON.parse(raw);
    if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
      return parsed;
    }
  } catch {}
  return null;
}

function normalizeText(raw) {
  let text = String(raw ?? '').trim();
  if (!text) {
    throw new Error('Design model output is empty.');
  }

  const fenced = text.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fenced) {
    text = fenced[1].trim();
  }

  return text;
}

function validateDsl(payload) {
  const requiredKeys = ['screens', 'modals', 'dialogs'];
  for (const key of requiredKeys) {
    if (!(key in payload)) {
      throw new Error(`Design DSL is missing '${key}'.`);
    }
    if (!Array.isArray(payload[key])) {
      throw new Error(`Design DSL key '${key}' must be an array.`);
    }
  }
}

function extractDsl(rawText) {
  const text = normalizeText(rawText);
  const candidates = [];

  candidates.push(text);

  const firstObjectStart = text.indexOf('{');
  const lastObjectEnd = text.lastIndexOf('}');
  if (firstObjectStart >= 0 && lastObjectEnd > firstObjectStart) {
    candidates.push(text.slice(firstObjectStart, lastObjectEnd + 1));
  }

  for (const candidate of candidates) {
    const parsed = parseCandidate(candidate);
    if (!parsed) continue;

    validateDsl(parsed);
    return parsed;
  }

  throw new Error('Could not extract valid DSL JSON from design model output.');
}

const item = $input.first();
const dsl = extractDsl(item?.json?.text);

return [{
  json: {
    designDsl: JSON.stringify(dsl),
    revisionNumber: Number(item?.json?.revisionNumber ?? 0) || 0,
  },
  binary: item?.binary ?? {},
}];

