function beCleanStructure() {
  function parseJsonCandidate(raw) {
    try {
      const parsed = JSON.parse(raw);
      if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
        return parsed;
      }
    } catch {}
    return null;
  }

  function normalizeText(raw) {
    let text = String(raw ?? '').trim();
    if (!text) {
      throw new Error('Backend structure model output is empty.');
    }

    if (text.startsWith('```')) {
      const firstNewlineIndex = text.indexOf('\n');
      if (firstNewlineIndex !== -1) {
        const openingFence = text.slice(0, firstNewlineIndex).trim();
        if (/^```(?:json)?$/i.test(openingFence)) {
          text = text.slice(firstNewlineIndex + 1);

          const trailingFenceIndex = text.lastIndexOf('\n```');
          if (trailingFenceIndex !== -1 && text.slice(trailingFenceIndex).trim() === '```') {
            text = text.slice(0, trailingFenceIndex).trim();
          } else if (text.endsWith('```')) {
            text = text.slice(0, -3).trim();
          } else {
            text = text.trim();
          }
        }
      }
    }

    return text;
  }

  function extractBalancedObject(text) {
    let depth = 0;
    let start = -1;
    let inString = false;
    let escaped = false;

    for (let index = 0; index < text.length; index += 1) {
      const char = text[index];

      if (escaped) {
        escaped = false;
        continue;
      }

      if (char === '\\') {
        if (inString) escaped = true;
        continue;
      }

      if (char === '"') {
        inString = !inString;
        continue;
      }

      if (inString) continue;

      if (char === '{') {
        if (depth === 0) start = index;
        depth += 1;
        continue;
      }

      if (char === '}') {
        if (depth > 0) {
          depth -= 1;
          if (depth === 0 && start !== -1) {
            return text.slice(start, index + 1);
          }
        }
      }
    }

    return null;
  }

  function extractStructure(rawText) {
    const text = normalizeText(rawText);
    const candidates = [text];
    const balancedObject = extractBalancedObject(text);
    if (balancedObject) {
      candidates.push(balancedObject);
    }

    for (const candidate of candidates) {
      const parsed = parseJsonCandidate(candidate);
      if (parsed) return parsed;
    }

    throw new Error('Could not extract a valid backend structure JSON document from model output.');
  }

  function normalizeFileEntry(file, index) {
    if (typeof file === 'string') {
      const path = file.trim();
      if (!path) {
        throw new Error(`files[${index}] must not be empty.`);
      }
      return { path };
    }

    if (!file || typeof file !== 'object' || Array.isArray(file)) {
      throw new Error(`files[${index}] must be a string path or an object with path.`);
    }

    const filePath = String(file.path || '').trim();
    if (!filePath) {
      throw new Error(`files[${index}].path is required.`);
    }

    return { path: filePath };
  }

  function validateAndNormalizeStructure(payload) {
    if (!payload || typeof payload !== 'object' || Array.isArray(payload)) {
      throw new Error('Backend structure must be an object.');
    }
    if (!Array.isArray(payload.files)) {
      throw new Error('Backend structure must contain a files array.');
    }
    if (!payload.files.length) {
      throw new Error('Backend structure files array must not be empty.');
    }

    const seen = new Set();
    const normalizedFiles = payload.files.map((file, index) => {
      const normalized = normalizeFileEntry(file, index);
      const filePath = normalized.path;
      if (!filePath.startsWith('backend/')) {
        throw new Error(`files[${index}].path must start with "backend/".`);
      }
      if (seen.has(filePath)) {
        throw new Error(`Duplicate backend structure file path: ${filePath}`);
      }
      seen.add(filePath);
      return normalized;
    });

    return { files: normalizedFiles };
  }

  const item = $input.first();
  const structure = validateAndNormalizeStructure(extractStructure(item?.json?.text));

  return [{
    json: {
      ...(item?.json ?? {}),
      backendStructure: JSON.stringify(structure, null, 2),
      backendStructureObject: structure,
      structureFileCount: structure.files.length,
    },
    binary: item?.binary ?? {},
  }];
}
return beCleanStructure();

function beInitGenerationState() {
  const item = $input.first();
  if (!item) {
    throw new Error('No backend structure item received.');
  }

  const json = item.json || {};
  const structure = json.backendStructureObject || JSON.parse(String(json.backendStructure || '{}'));
  if (!Array.isArray(structure.files) || !structure.files.length) {
    throw new Error('Backend structure does not contain any files.');
  }

  const seen = new Set();
  const files = structure.files.map((file, index) => {
    const filePath = typeof file === 'string'
      ? String(file).trim()
      : String(file?.path || '').trim();
    if (!filePath.startsWith('backend/')) {
      throw new Error(`Invalid backend structure path at index ${index}: ${filePath || '<empty>'}`);
    }
    if (seen.has(filePath)) {
      throw new Error(`Duplicate backend structure path: ${filePath}`);
    }
    seen.add(filePath);
    return { path: filePath };
  });

  return [{
    json: {
      ...json,
      allPlannedFiles: files,
      remainingFiles: files,
      generatedFiles: [],
      generatedFilePaths: [],
