  }

  const requirementsText = String(requirements.text || '').trim();
  const openapiText = String(openapi.text || '').trim();
  if (!requirementsText) {
    throw new Error('Requirements text is empty for infrastructure structure generation.');
  }
  if (!openapiText) {
