  }];
}

return await beBuildPrompt.call(this);

function beCleanStructure() {
  function parseJsonCandidate(raw) {
    try {
      const parsed = JSON.parse(raw);
      if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
        return parsed;
      }
    } catch {}
    return null;
  }

  function normalizeText(raw) {
    let text = String(raw ?? '').trim();
    if (!text) {
      throw new Error('Infrastructure structure model output is empty.');
    }

    if (text.startsWith('```')) {
      const firstNewlineIndex = text.indexOf('\n');
      if (firstNewlineIndex !== -1) {
        const openingFence = text.slice(0, firstNewlineIndex).trim();
        if (/^```(?:json)?$/i.test(openingFence)) {
          text = text.slice(firstNewlineIndex + 1);

          const trailingFenceIndex = text.lastIndexOf('\n```');
          if (trailingFenceIndex !== -1 && text.slice(trailingFenceIndex).trim() === '```') {
            text = text.slice(0, trailingFenceIndex).trim();
          } else if (text.endsWith('```')) {
            text = text.slice(0, -3).trim();
          } else {
            text = text.trim();
          }
        }
      }
    }

    return text;
  }

  function extractBalancedObject(text) {
    let depth = 0;
    let start = -1;
    let inString = false;
    let escaped = false;

    for (let index = 0; index < text.length; index += 1) {
      const char = text[index];

      if (escaped) {
        escaped = false;
        continue;
      }

      if (char === '\\') {
        if (inString) escaped = true;
        continue;
      }

      if (char === '"') {
        inString = !inString;
        continue;
      }

      if (inString) continue;

      if (char === '{') {
        if (depth === 0) start = index;
        depth += 1;
        continue;
      }

      if (char === '}') {
        if (depth > 0) {
          depth -= 1;
          if (depth === 0 && start !== -1) {
            return text.slice(start, index + 1);
          }
        }
      }
    }

    return null;
  }

  function extractStructure(rawText) {
    const text = normalizeText(rawText);
    const candidates = [text];
    const balancedObject = extractBalancedObject(text);
    if (balancedObject) {
      candidates.push(balancedObject);
    }

    for (const candidate of candidates) {
      const parsed = parseJsonCandidate(candidate);
      if (parsed) return parsed;
    }

    throw new Error('Could not extract a valid infrastructure structure JSON document from model output.');
  }

  function normalizeFileEntry(file, index) {
    if (typeof file === 'string') {
      const path = file.trim();
      if (!path) {
        throw new Error(`files[${index}] must not be empty.`);
      }
      return { path };
    }

    if (!file || typeof file !== 'object' || Array.isArray(file)) {
      throw new Error(`files[${index}] must be a string path or an object with path.`);
    }

    const filePath = String(file.path || '').trim();
    if (!filePath) {
      throw new Error(`files[${index}].path is required.`);
    }

    return { path: filePath };
  }

  function validateAndNormalizeStructure(payload) {
    if (!payload || typeof payload !== 'object' || Array.isArray(payload)) {
      throw new Error('Infrastructure structure must be an object.');
    }
    if (!Array.isArray(payload.files)) {
      throw new Error('Infrastructure structure must contain a files array.');
    }
    if (!payload.files.length) {
      throw new Error('Infrastructure structure files array must not be empty.');
    }

    const seen = new Set();
    const normalizedFiles = payload.files.map((file, index) => {
      const normalized = normalizeFileEntry(file, index);
      const filePath = normalized.path;
      if (!filePath.startsWith('infrastructure/')) {
        throw new Error(`files[${index}].path must start with "infrastructure/".`);
      }
      if (seen.has(filePath)) {
        throw new Error(`Duplicate infrastructure structure file path: ${filePath}`);
      }
      seen.add(filePath);
      return normalized;
    });

    return { files: normalizedFiles };
  }

  const item = $input.first();
  const structure = validateAndNormalizeStructure(extractStructure(item?.json?.text));

  return [{
    json: {
      ...(item?.json ?? {}),
      infrastructureStructure: JSON.stringify(structure, null, 2),
      infrastructureStructureObject: structure,
      structureFileCount: structure.files.length,
    },
    binary: item?.binary ?? {},
  }];
}
return beCleanStructure();

function beInitGenerationState() {
  const item = $input.first();
  if (!item) {
    throw new Error('No infrastructure structure item received.');
  }

  const json = item.json || {};
  const structure = json.infrastructureStructureObject || JSON.parse(String(json.infrastructureStructure || '{}'));
  if (!Array.isArray(structure.files) || !structure.files.length) {
    throw new Error('Infrastructure structure does not contain any files.');
  }

  const seen = new Set();
  const files = structure.files.map((file, index) => {
    const filePath = typeof file === 'string'
      ? String(file).trim()
      : String(file?.path || '').trim();
    if (!filePath.startsWith('infrastructure/')) {
      throw new Error(`Invalid infrastructure structure path at index ${index}: ${filePath || '<empty>'}`);
    }
    if (seen.has(filePath)) {
      throw new Error(`Duplicate infrastructure structure path: ${filePath}`);
    }
    seen.add(filePath);
    return { path: filePath };
  });

  return [{
    json: {
      ...json,
      allPlannedFiles: files,
      remainingFiles: files,
      generatedFiles: [],
      generatedFilePaths: [],
      lastIterationFiles: [],
      totalPlannedFiles: files.length,
      generatedFileCountTotal: 0,
      remainingFileCount: files.length,
      batchSize: 15,
      currentBatchFiles: files.slice(0, 15),
      currentBatchFileCount: Math.min(files.length, 15),
      iteration: 1,
      hasRemainingFiles: 'yes',
    },
    binary: item.binary ?? {},
  }];
}

return beInitGenerationState();

function beBuildChunkPrompt() {
  const MAX_MEMORY_ITEMS = 4;

  function compactJson(value) {
    return JSON.stringify(value);
  }

  function trimImplementationMemory(generatedImplementationIndex, recentImplementationSummaries) {
    const seen = new Set();
    const selected = [];

    for (const collection of [recentImplementationSummaries || [], generatedImplementationIndex || []]) {
      for (const entry of collection) {
        if (!entry || typeof entry !== 'object') continue;
        const path = String(entry.path || '').trim();
        if (!path || seen.has(path)) continue;
        seen.add(path);
        selected.push(entry);
        if (selected.length >= MAX_MEMORY_ITEMS) {
          return selected;
        }
      }
    }

    return selected;
  }

  return $input.all().map((item) => {
    const json = item.json || {};
    const requirementsText = String(json.requirementsText || '').trim();
    const openapiText = String(json.openapiText || '').trim();
    if (!requirementsText) throw new Error('Missing requirements text for infrastructure generation.');
    if (!openapiText) throw new Error('Missing OpenAPI text for infrastructure generation.');

    const batchSize = Math.max(1, Number(json.batchSize || 15));
    const currentBatchFiles = Array.isArray(json.currentBatchFiles) && json.currentBatchFiles.length
      ? json.currentBatchFiles.slice(0, batchSize)
      : (Array.isArray(json.remainingFiles) ? json.remainingFiles.slice(0, batchSize) : []);

    if (!currentBatchFiles.length) {
      throw new Error('No current batch files available for infrastructure generation.');
    }

    const allPlannedFiles = Array.isArray(json.allPlannedFiles) && json.allPlannedFiles.length
      ? json.allPlannedFiles
      : currentBatchFiles;
    const allPlannedPaths = allPlannedFiles
      .map((file) => String(file?.path || '').trim())
      .filter(Boolean);
    const batchPaths = currentBatchFiles
      .map((file) => String(file?.path || '').trim())
      .filter(Boolean);

    const implementationMemory = trimImplementationMemory(
      Array.isArray(json.generatedImplementationIndex) ? json.generatedImplementationIndex : [],
      Array.isArray(json.recentImplementationSummaries) ? json.recentImplementationSummaries : [],
    );

    const userPrompt = [
      'REQ',
      requirementsText,
      'API',
      openapiText,
      'PLAN',
      compactJson(allPlannedPaths),
      'BATCH',
      compactJson(batchPaths),
      'STATE',
      compactJson({
        i: json.iteration,
        g: json.generatedFileCountTotal,
        r: json.remainingFileCount,
        t: allPlannedPaths.length,
        b: batchSize,
        c: currentBatchFiles.length,
      }),
      implementationMemory.length ? 'MEMORY\n' + compactJson(implementationMemory) : '',
      'RULES',
      [
        'Generate only BATCH paths.',
        'PLAN is the full allowed infrastructure path set.',
        'Do not reference types or files outside BATCH, MEMORY, or PLAN.',
        'OpenAPI is absolute truth for paths, methods, params, bodies, fields, status codes, names, and security.',
        'Do not add or rewrite API path prefixes.',
        'Reuse existing naming and generated types consistently.',
        'Return only valid JSON with a top-level files array.',
      ].join('\n'),
    ].filter(Boolean).join('\n');

    return {
      json: {
        ...json,
        batchSize,
        allPlannedFiles,
        currentBatchFiles,
        currentBatchFileCount: currentBatchFiles.length,
        userPrompt,
        requirementsPromptLength: requirementsText.length,
        openapiPromptLength: openapiText.length,
        implementationMemoryLength: compactJson(implementationMemory).length,
        fullPromptLength: userPrompt.length,
      },
      binary: item.binary ?? {},
    };
  });
}

return beBuildChunkPrompt();

