        xml: 'application/xml',
        yaml: 'text/yaml',
        yml: 'text/yaml',
        json: 'application/json',
        properties: 'text/plain',
        md: 'text/markdown',
        txt: 'text/plain',
        sql: 'application/sql',
        csv: 'text/csv',
        gitignore: 'text/plain',
