  function cleanText(value) {
    return String(value || '').replace(/\s+/g, ' ').trim();
  }

  function slugify(value, fallback) {
    const text = cleanText(value).toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '');
