function feCleanChunkResponse() {
    function parseCandidate(raw) {
      try {
        const parsed = JSON.parse(raw);
        if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
          return parsed;
        }
      } catch {}
      return null;
    }

    function normalizeText(raw) {
      let text = String(raw ?? '').trim();
      if (!text) {
        throw new Error('Frontend chunk model output is empty.');
      }

      if (text.startsWith('```')) {
        const firstNewlineIndex = text.indexOf('\n');
        if (firstNewlineIndex !== -1) {
          const openingFence = text.slice(0, firstNewlineIndex).trim();
          if (/^\`\`\`(?:json)?$/i.test(openingFence)) {
            text = text.slice(firstNewlineIndex + 1);
            const trailingFenceIndex = text.lastIndexOf('\n\`\`\`');
            if (trailingFenceIndex !== -1 && text.slice(trailingFenceIndex).trim() === '```') {
              text = text.slice(0, trailingFenceIndex).trim();
            } else if (text.endsWith('```')) {
              text = text.slice(0, -3).trim();
            } else {
              text = text.trim();
            }
          }
        }
      }

      return text;
    }

    function extractBalancedObject(text) {
      let depth = 0;
      let start = -1;
      let inString = false;
      let escaped = false;

      for (let index = 0; index < text.length; index += 1) {
        const char = text[index];

        if (escaped) {
          escaped = false;
          continue;
        }

        if (char === '\\') {
          if (inString) escaped = true;
          continue;
        }

        if (char === '"') {
          inString = !inString;
          continue;
        }

        if (inString) continue;

        if (char === '{') {
          if (depth === 0) start = index;
          depth += 1;
          continue;
        }

        if (char === '}') {
          if (depth > 0) {
            depth -= 1;
            if (depth === 0 && start !== -1) {
              return text.slice(start, index + 1);
            }
          }
        }
      }

      return null;
    }

    function isQuoteEscaped(text, quoteIndex) {
      let backslashCount = 0;
      for (let index = quoteIndex - 1; index >= 0 && text[index] === '\\'; index -= 1) {
        backslashCount += 1;
      }
      return backslashCount % 2 === 1;
    }

    function findPropertyKey(text, key, fromIndex) {
      const pattern = '"' + key + '"';
      return text.indexOf(pattern, fromIndex);
    }

    function findValueStart(text, keyIndex) {
      const colonIndex = text.indexOf(':', keyIndex);
      if (colonIndex === -1) return -1;
      for (let index = colonIndex + 1; index < text.length; index += 1) {
        if (/\s/.test(text[index])) continue;
        return index;
      }
      return -1;
    }

    function decodeLooseJsonString(raw) {
      let output = '';

      for (let index = 0; index < raw.length; index += 1) {
        const char = raw[index];
        if (char !== '\\') {
          output += char;
          continue;
        }

        const next = raw[index + 1];
        if (next === undefined) {
          output += '\\';
          break;
        }

        if (next === 'n') {
          output += '\n';
          index += 1;
          continue;
        }
        if (next === 'r') {
          output += '\r';
          index += 1;
          continue;
        }
        if (next === 't') {
          output += '\t';
          index += 1;
          continue;
        }
        if (next === 'b') {
          output += '\b';
          index += 1;
          continue;
        }
        if (next === 'f') {
          output += '\f';
          index += 1;
          continue;
        }
        if (next === '"' || next === '\\' || next === '/') {
          output += next;
          index += 1;
          continue;
        }
        if (next === 'u' && /^[0-9a-fA-F]{4}$/.test(raw.slice(index + 2, index + 6))) {
          output += String.fromCharCode(parseInt(raw.slice(index + 2, index + 6), 16));
          index += 5;
          continue;
        }

        output += '\\' + next;
        index += 1;
      }

      return output;
    }

    function readStrictQuotedString(text, quoteStart) {
      for (let index = quoteStart + 1; index < text.length; index += 1) {
        if (text[index] === '"' && !isQuoteEscaped(text, index)) {
          return {
            value: decodeLooseJsonString(text.slice(quoteStart + 1, index)),
            endIndex: index,
          };
        }
      }
      throw new Error('Could not find closing quote for JSON string.');
    }

    function readStructuredJsonValue(text, valueStart) {
