function decodeEscapedText(text) {
  let value = String(text ?? '');
  for (let i = 0; i < 2; i += 1) {
    const trimmed = value.trim();
    if (!trimmed) return trimmed;
    if ((trimmed.startsWith('"') && trimmed.endsWith('"')) || (trimmed.startsWith("'") && trimmed.endsWith("'"))) {
      try {
        const parsed = JSON.parse(trimmed.startsWith("'") ? `"${trimmed.slice(1, -1).replace(/\\/g, '\\\\').replace(/"/g, '\\"')}"` : trimmed);
        if (typeof parsed === 'string') {
          value = parsed;
          continue;
        }
      } catch {}
    }
    if (trimmed.includes('\\n') || trimmed.includes('\\"') || trimmed.includes('\\t') || trimmed.includes('\\r')) {
      value = trimmed
        .replace(/\\r\\n/g, '\n')
        .replace(/\\n/g, '\n')
        .replace(/\\r/g, '\r')
        .replace(/\\t/g, '\t')
        .replace(/\\"/g, '"')
        .replace(/\\\\/g, '\\');
      continue;
    }
    break;
  }
  return value;
}

function normalizeText(raw) {
  let text = String(raw ?? '').trim();
  if (!text) {
    throw new Error('Infrastructure refinement plan model output is empty.');
  }
  text = decodeEscapedText(text).trim();
  const fenced = text.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fenced) {
    text = decodeEscapedText(fenced[1]).trim();
  }
  return text;
}

function parseJsonCandidates(text) {
  const normalized = normalizeText(text);
  const candidates = [normalized];
  const objectStart = normalized.indexOf('{');
  const objectEnd = normalized.lastIndexOf('}');
  if (objectStart >= 0 && objectEnd > objectStart) {
    candidates.push(normalized.slice(objectStart, objectEnd + 1));
  }
  const arrayStart = normalized.indexOf('[');
  const arrayEnd = normalized.lastIndexOf(']');
  if (arrayStart >= 0 && arrayEnd > arrayStart) {
    candidates.push(normalized.slice(arrayStart, arrayEnd + 1));
  }
  for (const candidate of candidates) {
    try {
      return JSON.parse(candidate);
    } catch {}
  }
  return null;
}

function normalizeAction(value) {
  const action = String(value ?? '').trim().toLowerCase();
  if (!action) return '';
  if (['modify', 'modified', 'update', 'updated', 'change', 'changed', 'edit', 'edited', 'patch', 'replace'].includes(action)) {
    return 'modify';
  }
  if (['create', 'created', 'add', 'added', 'new', 'insert'].includes(action)) {
    return 'create';
  }
  if (['remove', 'removed', 'delete', 'deleted', 'drop'].includes(action)) {
    return 'remove';
  }
  return '';
}

function extractEntriesFromObjectMap(payload) {
  if (!payload || typeof payload !== 'object' || Array.isArray(payload)) return [];
  const entries = [];
  for (const [key, value] of Object.entries(payload)) {
    const path = String(key ?? '').trim();
    if (!path.startsWith('infrastructure/')) continue;
    if (typeof value === 'string') {
      const action = normalizeAction(value);
      if (action) entries.push({ path, action });
      continue;
    }
    if (value && typeof value === 'object') {
      const action = normalizeAction(value.action ?? value.type ?? value.operation ?? value.op);
      if (action) entries.push({ path, action });
    }
  }
  return entries;
}

function extractRegexEntries(text) {
  const normalized = normalizeText(text);
  const results = [];
  const pattern = /"path"\s*:\s*"([^"]+)"[\s,;\r\n]*"action"\s*:\s*"([^"]+)"/gi;
  for (const match of normalized.matchAll(pattern)) {
    results.push({ path: match[1], action: match[2] });
  }
  return results;
}

function collectRawFiles(payload, originalText) {
  if (Array.isArray(payload)) return payload;
  if (Array.isArray(payload?.files)) return payload.files;
  if (Array.isArray(payload?.changes)) return payload.changes;
  if (Array.isArray(payload?.items)) return payload.items;
  if (Array.isArray(payload?.actions)) return payload.actions;
  const objectMapEntries = extractEntriesFromObjectMap(payload);
  if (objectMapEntries.length) return objectMapEntries;
  const regexEntries = extractRegexEntries(originalText);
  if (regexEntries.length) return regexEntries;
  return [];
}

function normalizePlan(payload, originalText) {
  const rawFiles = collectRawFiles(payload, originalText);
  const seen = new Set();
  const files = [];
  for (const entry of rawFiles) {
    if (!entry || typeof entry !== 'object') continue;
    const path = String(entry.path ?? entry.file ?? entry.filePath ?? '').trim();
    const action = normalizeAction(entry.action ?? entry.type ?? entry.operation ?? entry.op);
    if (!path || !path.startsWith('infrastructure/')) continue;
    if (!action) continue;
    if (seen.has(path)) continue;
    seen.add(path);
    files.push({ path, action });
  }
  if (!files.length) {
    throw new Error('Infrastructure refinement plan did not contain any valid file actions.');
  }
  return { files };
}

