    const byPath = new Map();
    for (const [propertyName, entry] of Object.entries(binary || {})) {
      if (propertyName === 'infrastructureZip' || propertyName === 'infrastructureStructure') continue;
      const fileName = String(entry?.fileName ?? '').trim();
      const normalizedPath = normalizeInfrastructurePath(fileName, infrastructureRoot, entry?.directory);
      const isDecompressedEntry = /^current_/i.test(propertyName) || String(entry?.directory ?? '').replace(/\\/g, '/').trim() === infrastructureRoot;
      if ((!isDecompressedEntry && !normalizedPath.startsWith(infrastructureRoot + '/')) || !normalizedPath || normalizedPath.endsWith('.zip')) continue;
