    if (!entry || typeof entry !== 'object') continue;
    const path = String(entry.path ?? '').trim();
    const action = String(entry.action ?? '').trim().toLowerCase();
    if (!path.startsWith('infrastructure/') || !allowedActions.has(action) || seenPlanPaths.has(path)) continue;
    seenPlanPaths.add(path);
    refinementPlanFiles.push({ path, action });
  }
  if (!refinementPlanFiles.length) {
    throw new Error('Infrastructure refinement plan did not contain any valid file actions.');
  }

  const infrastructureRoot = String(json.infrastructureRoot ?? 'infrastructure').trim() || 'infrastructure';
  const infrastructureFiles = await collectCurrentInfrastructureFiles.call(this, binary, infrastructureRoot);
  if (!infrastructureFiles.length) {
    throw new Error('Current infrastructure ZIP could not be unpacked into files for refinement.');
  }
  const infrastructureFileMap = new Map(infrastructureFiles.map((file) => [file.path, file]));
  const structureTextCandidates = [
